#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char A[N + 1];
        scanf("%s", A);

        for (int i = 0; i < M; i++) {
            int type, X, Y;
            scanf("%d %d %d", &type, &X, &Y);

            if (type == 1) {
                A[X - 1] = Y + '0';
            } else {
                int count = 0;
                for (int j = X - 1; j <= Y - 1; j++) {
                    for (int k = j; k <= Y - 1; k++) {
                        int sum = 0;
                        for (int l = j; l <= k; l++) {
                            sum += A[l] - '0';
                        }
                        if (sum % 3 == 0) {
                            count++;
                        }
                    }
                }
                printf("%d\n", count);
            }
        }
    }

    return 0;
}

