import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            String A = sc.next();

            for (int i = 0; i < M; i++) {
                int type = sc.nextInt();
                int X = sc.nextInt();
                int Y = sc.nextInt();

                if (type == 1) {
                    A = A.substring(0, X - 1) + Y + A.substring(X);
                } else {
                    int count = 0;
                    for (int j = X - 1; j <= Y - 1; j++) {
                        for (int k = j; k <= Y - 1; k++) {
                            int sum = 0;
                            for (int l = j; l <= k; l++) {
                                sum += A.charAt(l) - '0';
                            }
                            if (sum % 3 == 0) {
                                count++;
                            }
                        }
                    }
                    System.out.println(count);
                }
            }
        }
    }
}

